/**
 * Vendored monochrome brand glyphs for every agent type Herdr supports
 * (https://herdr.dev/docs/agents/#supported-agents), tinted at render time via
 * theme tokens — same approach as CodexBar"s template-image provider icons.
 *
 * Sources:
 * - Simple Icons (CC0): claude, gemini (googlegemini), copilot (githubcopilot),
 *   cursor, opencode, ollama, deepseek, mistral (mistralai), pi (pi.dev),
 *   kimi, cline
 * - LobeHub icons-static-svg (MIT): openai (also shown for codex), devin, hermes (hermesagent),
 *   qoder, kilocode, mastra, amp, grok, antigravity, kiro
 * - omp.sh favicon: omp (the Oh My Pi glyph)
 * - CodexBar Resources (MIT): droid (Factory)
 *
 * Maki has no vector mark published, so it falls through to the generic
 * terminal icon. Data is copied rather than importing the icon packages so the
 * bundle only carries the glyphs the app can actually show.
 */

export interface BrandGlyph {
  /** SVG path data. */
  d: string;
  /** Coordinate space of the path. Defaults to the common "0 0 24 24". */
  viewBox?: string;
}

