type BrandGlyphName = keyof typeof glyphs;

/**
 * Ordered matching rules; first match wins. Long needles match as substrings
 * so "claudecode" still resolves to claude; short ones ("pi", "omp", "amp",
 * "gpt") match whole words only so they don’t fire inside longer names
 * ("copilot" contains "pi").
 */
const matchers: readonly [string, BrandGlyphName][] = [
  ["claude", "claude"],
  ["codex", "openai"],
  ["openai", "openai"],
  ["gemini", "gemini"],
  ["copilot", "copilot"],
  ["cursor", "cursor"],
  ["opencode", "opencode"],
  ["ollama", "ollama"],
  ["deepseek", "deepseek"],
  ["mistral", "mistral"],
  ["kimi", "kimi"],
  ["cline", "cline"],
  ["devin", "devin"],
  ["hermes", "hermes"],
  ["qoder", "qoder"],
  ["kilo", "kilocode"],
  ["mastra", "mastra"],
  ["grok", "grok"],
  ["antigravity", "antigravity"],
  ["kiro", "kiro"],
  ["droid", "droid"],
  ["factory", "droid"],
  ["gpt", "openai"],
  ["amp", "amp"],
  ["omp", "omp"],
  ["pi", "pi"],
];

/**
 * Resolve an agent name (free-form string from the daemon, e.g. "claude",
 * "codex") to a brand glyph. Returns undefined for unknown agents so callers
 * can fall back to a generic terminal icon.
 */
export function brandGlyphForAgent(agentName: string | undefined): BrandGlyph | undefined {
  if (!agentName) return undefined;
  const name = agentName.toLowerCase();
  const words = name.split(/[^a-z0-9]+/);
  for (const [needle, glyph] of matchers) {
    const hit = needle.length >= 4 ? name.includes(needle) : words.includes(needle);
    if (hit) return glyphs[glyph];
  }
  return undefined;
}
